CREATE TABLE IF NOT EXISTS `{prefix}_conversations` ( `id` int(11) NOT NULL AUTO_INCREMENT, `subject` varchar(255) NOT NULL, `sender_id` int(11) NOT NULL, `recipient_id` int(11) NOT NULL, `created_at` int(11) NOT NULL, `updated_at` int(11) NOT NULL, PRIMARY KEY (`id`), KEY `sender_id` (`sender_id`), KEY `recipient_id` (`recipient_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_conversation_users` ( `conversation_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `last_read_at` int(11) DEFAULT '0', `is_deleted` tinyint(1) DEFAULT '0', PRIMARY KEY (`conversation_id`,`user_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_conversations_messages` ( `id` int(11) NOT NULL AUTO_INCREMENT, `conversation_id` int(11) NOT NULL, `sender_id` int(11) NOT NULL, `content` text NOT NULL, `created_at` int(11) NOT NULL, PRIMARY KEY (`id`), KEY `conversation_id` (`conversation_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
